var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"그때 시선이 느껴졌어. 선체 아래의 바다에서 고래 몸집만 한 게 꿈틀대고 있었지.","JPN":"その時、視線を感じたんだ。船の下の海でクジラのような大きさの何かがうごめいたんだ。","ENG":"That's when I felt its gaze. Something under the ship, as big as a whale, was squirming.","TWN":"那個時候，我感覺到有什麼東西在盯著我，船身底下的水中有一條鯨魚大小的東西在蠕動。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"그건 생물의 눈동자였어. 엄청나게 거대한.","JPN":"それは生物の目だったんだ。とてつもなくデカい。","ENG":"It was an eye of a creature. A huge one at that.","TWN":"那是一種生物的眼睛，一雙非常大的眼睛。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"눈이라고? 정신없어서 헛것을 본 거 아냐?","JPN":"目だと？　慌てて変なものを見たんじゃないか？","ENG":"An eye? Are you sure you weren't hallucinating?","TWN":"眼睛？會不會是你眼花看錯？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"아냐, 똑똑히 봤어. 그런 소름 끼치는 걸 어떻게 잊겠냐고.","JPN":"いいや、確かに見た。あんな不気味なものは忘れられないよ。","ENG":"No, I saw it clear as day. How would I forget such a terrifying thing?","TWN":"不，我看得很清楚。那種毛骨悚然的感覺，我一輩子也忘不掉。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_CAREFUL","text":{"KOREA":"다른 녀석들 사이에서도 여러 목격담이 돌고 있더군. 집채만 한 꼬리가 선체를 노크하듯 두드렸다고도 하던데.","JPN":"他のやつらからも色々目撃したって話が出ている。家みたいな大きさの尻尾が船をノックするかのように叩いたとか。","ENG":"There are quite a few stories about its sightings. I heard a colossal tail hit the ship like it was knocking on a door.","TWN":"還有一些人也有目擊到，他們看到有一個房子大小的尾巴不停地敲擊著船身。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_CAREFUL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_CAREFUL","text":{"KOREA":"비명소리와 함께 연락이 두절된 팀도 있다는 모양이야.","JPN":"悲鳴と共に連絡が取れなくなったチームもあるらしい。","ENG":"Seems like some teams went missing after their last screams were heard through the radio.","TWN":"似乎還有些人，一邊慘叫一邊消失不見。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_CAREFUL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"역시 포기하는 게 좋겠어. 검은 범람을 뚫고 항해를 계속하는 건 무모한 짓이야.","JPN":"やっぱり諦めた方がいい。黒い氾濫の中を航海するのは無茶だ。","ENG":"We should give up. It's reckless to keep sailing through the Black Flood.","TWN":"還是放棄吧，繼續在黑色洪災中航行是非常不明智的行為。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"쳇, 다른 녀석들이 겁주려고 퍼트리는 헛소문이겠지.","JPN":"ちっ、他のやつらが怖がすためにばら撒いた噂だろう。","ENG":"Tsk. It's probably just a rumor they're spreading to scare others.","TWN":"嘖，這是他們想嚇退其他人而散布的謠言吧。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_CAREFUL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"자기들끼리 토큰을 독차지하려고 괜한 수작부리는 거라고.","JPN":"自分たちでトークンを独り占めしようと手を打ったんだ。","ENG":"They're just playing tricks so they can hog all the tokens.","TWN":"是不是想獨吞賞金才耍這種小手段。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_CAREFUL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_CAREFUL","text":{"KOREA":"하지만 너도 느꼈잖아. 그 음산한 검은빛은 우리가 알던 바다가 아니었어.","JPN":"でもお前も感じただろう。あの気持ち悪い黒色は俺らが知っていた海じゃなかったんだ。","ENG":"But you felt it too, right? That creepy black hue isn't the ocean we know of.","TWN":"你不是也有感覺到嗎？那散發著陰森黑色光芒的大海，不是我們所熟悉的大海。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_CAREFUL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That's...","TWN":"這…"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_CAREFUL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_CAREFUL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"정말이야? 심해역에서 살아 돌아온 생존자라고?","JPN":"本当か？　深海域から生きて帰ってきた生存者だと？","ENG":"Is it true? They survived the deep sea area?","TWN":"你說真的？有人活著從深海域回來？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"살아 돌아온 것만이 아니야. 보물들을 잔뜩 싣고 왔어.","JPN":"ただ生きて帰ってきたんじゃない。宝物もたくさん持ってきたんだ。","ENG":"Not just survived. He brought a bunch of treasures with him.","TWN":"他不只活著回來，還帶回來不少的寶藏。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL2","text":{"KOREA":"자기가 보물사냥꾼이라고 하던데?","JPN":"自分をトレジャーハンターと名乗っていたぜ？","ENG":"Calls himself a treasure hunter.","TWN":"他自稱是寶藏獵人？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"보물사냥꾼…?","JPN":"トレジャーハンター……？","ENG":"Treasure hunter...?","TWN":"寶藏獵人…？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"당신, 그게 정말인가?","JPN":"アンタ、それは本当か？","ENG":"Hey, is it true?","TWN":"我問你，都是真的嗎？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"그 값진 유물들을 전부 심해역에서 건졌다고?","JPN":"その高そうな宝を全部深海域から手に入れたって？","ENG":"You got all those valuables from the deep sea area?","TWN":"這些值錢的東西都是從深海域裡打撈上來的？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그래. 전부 검은 범람과 함께 심해의 밑바닥에서 떠오른 것들이지.","JPN":"そう。全部黒い氾濫と共に深海の底から浮上したものだ。","ENG":"Aye. They all emerged from the depths of the ocean alongside the Black Flood.","TWN":"沒錯，這些東西都是隨著黑色洪災從海底浮上來的。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"에이버리의 함선을 찾다가 배가 고장이 나버려서, 아쉬운 대로 챙겨온 것들이야.","JPN":"エイバリーの艦船を探していたら船が壊れてしまって、できるだけ持ってきたものだ。","ENG":"We were looking for Avery's ship, but our ship broke down. It's not a lot, but these are what we brought back.","TWN":"在尋找艾維利的艦船時我們的船壞掉，所以很可惜只能帶回這點東西。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};